import type { Request, Response } from "express";


type ProductQuery = {
  text: string;
  filters: Record<string, string[]>;
  limit: number;
};

export async function searchProducts(request: Request, response: Response) {
  const query: ProductQuery = parseNaturalLanguageQuery(request.body.query);

  const products = await productCollection
    .find(buildMongoFilters(query.filters))
    .limit(query.limit)
    .toArray();

  const rankedProducts = rankByIntent(products, query.text);

  response.json({
    query,
    results: rankedProducts,
    total: rankedProducts.length,
  });
}
